        'customer was charged twice and asks for their money back',
        'billing refund'
    ) INTO score;
    IF score < 0 OR score > 1 THEN
        RAISE EXCEPTION 'bundled semantic_score out of range: %', score;
    END IF;

    SELECT rvbbit.means(
        'customer was charged twice and asks for their money back',
        'billing refund'
    ) INTO matched;
    IF matched IS NULL THEN
        RAISE EXCEPTION 'bundled means operator returned NULL';
    END IF;

    SELECT rvbbit.semantic_matches(
        'customer was charged twice and asks for their money back',
        'billing refund',
        '{"threshold":0.1}'::jsonb
    ) INTO matched;
    IF matched IS NULL THEN
        RAISE EXCEPTION 'bundled semantic_matches operator returned NULL';
    END IF;
END
$$;

